6: import { localize } from '../../../nls.js';
7: import { IMarkerData, MarkerSeverity } from '../../../platform/markers/common/markers.js';
8: import { URI, UriComponents } from '../../../base/common/uri.js';
9: import type * as vscode from 'vscode';
10: import { MainContext, MainThreadDiagnosticsShape, ExtHostDiagnosticsShape, IMainContext } from './extHost.protocol.js';
11: import { DiagnosticSeverity } from './extHostTypes.js';
12: import * as converter from './extHostTypeConverters.js';
13: import { Event, Emitter, DebounceEmitter } from '../../../base/common/event.js';
14: import { coalesce } from '../../../base/common/arrays.js';
15: import { ILogService } from '../../../platform/log/common/log.js';
16: import { ResourceMap } from '../../../base/common/map.js';
17: import { ExtensionIdentifier } from '../../../platform/extensions/common/extensions.js';
18: import { IExtHostFileSystemInfo } from './extHostFileSystemInfo.js';
19: import { IExtUri } from '../../../base/common/resources.js';
20: import { ExtHostDocumentsAndEditors } from './extHostDocumentsAndEditors.js';
21: 
22: export class DiagnosticCollection implements vscode.DiagnosticCollection {
23: 
24: 	readonly #proxy: MainThreadDiagnosticsShape | undefined;
25: 	readonly #onDidChangeDiagnostics: Emitter<readonly vscode.Uri[]>;
26: 	readonly #data: ResourceMap<vscode.Diagnostic[]>;
27: 
28: 	private _isDisposed = false;
29: 
30: 	constructor(
31: 		private readonly _name: string,
32: 		private readonly _owner: string,
33: 		private readonly _maxDiagnosticsTotal: number,
34: 		private readonly _maxDiagnosticsPerFile: number,
35: 		private readonly _modelVersionIdProvider: (uri: URI) => number | undefined,
36: 		extUri: IExtUri,
37: 		proxy: MainThreadDiagnosticsShape | undefined,
38: 		onDidChangeDiagnostics: Emitter<readonly vscode.Uri[]>
39: 	) {
40: 		this._maxDiagnosticsTotal = Math.max(_maxDiagnosticsPerFile, _maxDiagnosticsTotal);
41: 		this.#data = new ResourceMap(uri => extUri.getComparisonKey(uri));
42: 		this.#proxy = proxy;
43: 		this.#onDidChangeDiagnostics = onDidChangeDiagnostics;
44: 	}
45: 
46: 	dispose(): void {
47: 		if (!this._isDisposed) {
48: 			this.#onDidChangeDiagnostics.fire([...this.#data.keys()]);
49: 			this.#proxy?.$clear(this._owner);
50: 			this.#data.clear();
51: 			this._isDisposed = true;
52: 		}
53: 	}
54: 
55: 	get name(): string {
56: 		this._checkDisposed();
57: 		return this._name;
58: 	}
59: 
60: 	set(uri: vscode.Uri, diagnostics: ReadonlyArray<vscode.Diagnostic>): void;
61: 	set(entries: ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]>): void;
62: 	set(first: vscode.Uri | ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]>, diagnostics?: ReadonlyArray<vscode.Diagnostic>) {
63: 
64: 		if (!first) {
65: 			// this set-call is a clear-call
66: 			this.clear();
67: 			return;
68: 		}
69: 
70: 		// the actual implementation for #set
71: 
72: 		this._checkDisposed();
73: 		let toSync: vscode.Uri[] = [];
74: 
75: 		if (URI.isUri(first)) {
76: 
77: 			if (!diagnostics) {
78: 				// remove this entry
79: 				this.delete(first);
80: 				return;
81: 			}
82: 
83: 			// update single row
84: 			this.#data.set(first, coalesce(diagnostics));
85: 			toSync = [first];
86: 
87: 		} else if (Array.isArray(first)) {
88: 			// update many rows
89: 			toSync = [];
90: 			let lastUri: vscode.Uri | undefined;
91: 
92: 			// ensure stable-sort
93: 			first = [...first].sort(DiagnosticCollection._compareIndexedTuplesByUri);
94: 
95: 			for (const tuple of first) {
96: 				const [uri, diagnostics] = tuple;
97: 				if (!lastUri || uri.toString() !== lastUri.toString()) {
98: 					if (lastUri && this.#data.get(lastUri)!.length === 0) {
99: 						this.#data.delete(lastUri);
100: 					}
101: 					lastUri = uri;
102: 					toSync.push(uri);
103: 					this.#data.set(uri, []);
104: 				}
105: 
106: 				if (!diagnostics) {
107: 					// [Uri, undefined] means clear this
108: 					const currentDiagnostics = this.#data.get(uri);
109: 					if (currentDiagnostics) {
110: 						currentDiagnostics.length = 0;
111: 					}
112: 				} else {
113: 					const currentDiagnostics = this.#data.get(uri);
114: 					currentDiagnostics?.push(...coalesce(diagnostics));
115: 				}
116: 			}
117: 		}
118: 
119: 		// send event for extensions
120: 		this.#onDidChangeDiagnostics.fire(toSync);
121: 
122: 		// compute change and send to main side
123: 		if (!this.#proxy) {
124: 			return;
125: 		}
126: 		const entries: [URI, IMarkerData[]][] = [];
127: 		let totalMarkerCount = 0;
128: 		for (const uri of toSync) {
129: 			let marker: IMarkerData[] = [];
130: 			const diagnostics = this.#data.get(uri);
131: 			if (diagnostics) {
132: 
133: 				// no more than N diagnostics per file
134: 				if (diagnostics.length > this._maxDiagnosticsPerFile) {
135: 					marker = [];
136: 					const order = [DiagnosticSeverity.Error, DiagnosticSeverity.Warning, DiagnosticSeverity.Information, DiagnosticSeverity.Hint];
137: 					orderLoop: for (let i = 0; i < 4; i++) {
138: 						for (const diagnostic of diagnostics) {
139: 							if (diagnostic.severity === order[i]) {
140: 								const len = marker.push({ ...converter.Diagnostic.from(diagnostic), modelVersionId: this._modelVersionIdProvider(uri) });
141: 								if (len === this._maxDiagnosticsPerFile) {
142: 									break orderLoop;
143: 								}
144: 							}
145: 						}
146: 					}
147: 
148: 					// add 'signal' marker for showing omitted errors/warnings
149: 					marker.push({
150: 						severity: MarkerSeverity.Info,
151: 						message: localize({ key: 'limitHit', comment: ['amount of errors/warning skipped due to limits'] }, "Not showing {0} further errors and warnings.", diagnostics.length - this._maxDiagnosticsPerFile),
152: 						startLineNumber: marker[marker.length - 1].startLineNumber,
153: 						startColumn: marker[marker.length - 1].startColumn,
154: 						endLineNumber: marker[marker.length - 1].endLineNumber,
155: 						endColumn: marker[marker.length - 1].endColumn
156: 					});
157: 				} else {
158: 					marker = diagnostics.map(diag => ({ ...converter.Diagnostic.from(diag), modelVersionId: this._modelVersionIdProvider(uri) }));
159: 				}
160: 			}
161: 
162: 			entries.push([uri, marker]);
163: 
164: 			totalMarkerCount += marker.length;
165: 			if (totalMarkerCount > this._maxDiagnosticsTotal) {
166: 				// ignore markers that are above the limit
167: 				break;
168: 			}
169: 		}
170: 		this.#proxy.$changeMany(this._owner, entries);
171: 	}
172: 
173: 	delete(uri: vscode.Uri): void {
174: 		this._checkDisposed();
175: 		this.#onDidChangeDiagnostics.fire([uri]);
176: 		this.#data.delete(uri);
177: 		this.#proxy?.$changeMany(this._owner, [[uri, undefined]]);
178: 	}
179: 
180: 	clear(): void {
181: 		this._checkDisposed();
182: 		this.#onDidChangeDiagnostics.fire([...this.#data.keys()]);
183: 		this.#data.clear();
184: 		this.#proxy?.$clear(this._owner);
185: 	}
186: 
187: 	forEach(callback: (uri: URI, diagnostics: ReadonlyArray<vscode.Diagnostic>, collection: DiagnosticCollection) => unknown, thisArg?: unknown): void {
188: 		this._checkDisposed();
189: 		for (const [uri, values] of this) {
190: 			callback.call(thisArg, uri, values, this);
191: 		}
192: 	}
193: 
194: 	*[Symbol.iterator](): IterableIterator<[uri: vscode.Uri, diagnostics: readonly vscode.Diagnostic[]]> {
195: 		this._checkDisposed();
196: 		for (const uri of this.#data.keys()) {
197: 			yield [uri, this.get(uri)];
198: 		}
199: 	}
200: 
201: 	get(uri: URI): ReadonlyArray<vscode.Diagnostic> {
202: 		this._checkDisposed();
203: 		const result = this.#data.get(uri);
204: 		if (Array.isArray(result)) {
205: 			return Object.freeze(result.slice(0));
206: 		}
207: 		return [];
208: 	}
209: 
210: 	has(uri: URI): boolean {
211: 		this._checkDisposed();
212: 		return Array.isArray(this.#data.get(uri));
213: 	}
214: 
215: 	private _checkDisposed() {
216: 		if (this._isDisposed) {
217: 			throw new Error('illegal state - object is disposed');
218: 		}
219: 	}
220: 
221: 	private static _compareIndexedTuplesByUri(a: [vscode.Uri, readonly vscode.Diagnostic[]], b: [vscode.Uri, readonly vscode.Diagnostic[]]): number {
222: 		if (a[0].toString() < b[0].toString()) {
223: 			return -1;
224: 		} else if (a[0].toString() > b[0].toString()) {
225: 			return 1;
226: 		} else {
227: 			return 0;
228: 		}
229: 	}
230: }
231: 
232: export class ExtHostDiagnostics implements ExtHostDiagnosticsShape {
233: 
234: 	private static _idPool: number = 0;
235: 	private static readonly _maxDiagnosticsPerFile: number = 1000;
236: 	private static readonly _maxDiagnosticsTotal: number = 1.1 * this._maxDiagnosticsPerFile;
237: 
238: 	private readonly _proxy: MainThreadDiagnosticsShape;
239: 	private readonly _collections = new Map<string, DiagnosticCollection>();
240: 	private readonly _onDidChangeDiagnostics = new DebounceEmitter<readonly vscode.Uri[]>({ merge: all => all.flat(), delay: 50 });
241: 
242: 	static _mapper(last: readonly vscode.Uri[]): { uris: readonly vscode.Uri[] } {
243: 		const map = new ResourceMap<vscode.Uri>();
244: 		for (const uri of last) {
245: 			map.set(uri, uri);
246: 		}
247: 		return { uris: Object.freeze(Array.from(map.values())) };
248: 	}
249: 
250: 	readonly onDidChangeDiagnostics: Event<vscode.DiagnosticChangeEvent> = Event.map(this._onDidChangeDiagnostics.event, ExtHostDiagnostics._mapper);
251: 
252: 	constructor(
253: 		mainContext: IMainContext,
254: 		@ILogService private readonly _logService: ILogService,
255: 		@IExtHostFileSystemInfo private readonly _fileSystemInfoService: IExtHostFileSystemInfo,
256: 		private readonly _extHostDocumentsAndEditors: ExtHostDocumentsAndEditors,
257: 	) {
258: 		this._proxy = mainContext.getProxy(MainContext.MainThreadDiagnostics);
259: 	}
260: 
261: 	createDiagnosticCollection(extensionId: ExtensionIdentifier, name?: string): vscode.DiagnosticCollection {
262: 
263: 		const { _collections, _proxy, _onDidChangeDiagnostics, _logService, _fileSystemInfoService, _extHostDocumentsAndEditors } = this;
264: 
265: 		const loggingProxy = new class implements MainThreadDiagnosticsShape {
266: 			$changeMany(owner: string, entries: [UriComponents, IMarkerData[] | undefined][]): void {
267: 				_proxy.$changeMany(owner, entries);
268: 				_logService.trace('[DiagnosticCollection] change many (extension, owner, uris)', extensionId.value, owner, entries.length === 0 ? 'CLEARING' : entries);
269: 			}
270: 			$clear(owner: string): void {
271: 				_proxy.$clear(owner);
272: 				_logService.trace('[DiagnosticCollection] remove all (extension, owner)', extensionId.value, owner);
273: 			}
274: 			dispose(): void {
275: 				_proxy.dispose();
276: 			}
277: 		};
278: 
279: 
280: 		let owner: string;
281: 		if (!name) {
282: 			name = '_generated_diagnostic_collection_name_#' + ExtHostDiagnostics._idPool++;
283: 			owner = name;
284: 		} else if (!_collections.has(name)) {
285: 			owner = name;
286: 		} else {
287: 			this._logService.warn(`DiagnosticCollection with name '${name}' does already exist.`);
288: 			do {
289: 				owner = name + ExtHostDiagnostics._idPool++;
290: 			} while (_collections.has(owner));
291: 		}
292: 
293: 		const result = new class extends DiagnosticCollection {
294: 			constructor() {
295: 				super(
296: 					name!, owner,
297: 					ExtHostDiagnostics._maxDiagnosticsTotal,
298: 					ExtHostDiagnostics._maxDiagnosticsPerFile,
299: 					uri => _extHostDocumentsAndEditors.getDocument(uri)?.version,
300: 					_fileSystemInfoService.extUri, loggingProxy, _onDidChangeDiagnostics
301: 				);
302: 				_collections.set(owner, this);
303: 			}
304: 			override dispose() {
305: 				super.dispose();
306: 				_collections.delete(owner);
307: 			}
308: 		};
309: 
310: 		return result;
311: 	}
312: 
313: 	getDiagnostics(resource: vscode.Uri): ReadonlyArray<vscode.Diagnostic>;
314: 	getDiagnostics(): ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]>;
315: 	getDiagnostics(resource?: vscode.Uri): ReadonlyArray<vscode.Diagnostic> | ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]>;
316: 	getDiagnostics(resource?: vscode.Uri): ReadonlyArray<vscode.Diagnostic> | ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]> {
317: 		if (resource) {
318: 			return this._getDiagnostics(resource);
319: 		} else {
320: 			const index = new Map<string, number>();
321: 			const res: [vscode.Uri, vscode.Diagnostic[]][] = [];
322: 			for (const collection of this._collections.values()) {
323: 				collection.forEach((uri, diagnostics) => {
324: 					let idx = index.get(uri.toString());
325: 					if (typeof idx === 'undefined') {
326: 						idx = res.length;
327: 						index.set(uri.toString(), idx);
328: 						res.push([uri, []]);
329: 					}
330: 					res[idx][1] = res[idx][1].concat(...diagnostics);
331: 				});
332: 			}
333: 			return res;
334: 		}
335: 	}
336: 
337: 	private _getDiagnostics(resource: vscode.Uri): ReadonlyArray<vscode.Diagnostic> {
338: 		let res: vscode.Diagnostic[] = [];
339: 		for (const collection of this._collections.values()) {
340: 			if (collection.has(resource)) {
341: 				res = res.concat(collection.get(resource));
342: 			}
343: 		}
344: 		return res;
345: 	}
346: 
347: 	private _mirrorCollection: vscode.DiagnosticCollection | undefined;
348: 
349: 	$acceptMarkersChange(data: [UriComponents, IMarkerData[]][]): void {
350: 
351: 		if (!this._mirrorCollection) {
352: 			const name = '_generated_mirror';
353: 			const collection = new DiagnosticCollection(
354: 				name, name,
355: 				Number.MAX_SAFE_INTEGER, Number.MAX_SAFE_INTEGER, // no limits because this collection is just a mirror of "sanitized" data
356: 				_uri => undefined,
357: 				this._fileSystemInfoService.extUri, undefined, this._onDidChangeDiagnostics
358: 			);
359: 			this._collections.set(name, collection);
360: 			this._mirrorCollection = collection;
361: 		}
362: 
363: 		for (const [uri, markers] of data) {
364: 			this._mirrorCollection.set(URI.revive(uri), markers.map(converter.Diagnostic.to));
365: 		}
366: 	}
