369: 	public deleteAllDiagnosticsInFile(resource: vscode.Uri): void {
370: 		this._currentDiagnostics.delete(resource);
371: 		this._diagnostics.delete(resource);
372: 	}
373: 
374: 	public deleteDiagnostic(resource: vscode.Uri, diagnostic: vscode.Diagnostic): void {
