276: 	private tsDiagnosticToVsDiagnostic(diagnostic: Proto.Diagnostic, source: string): vscode.Diagnostic & { reportUnnecessary: any; reportDeprecated: any } {
277: 		const { start, end, text } = diagnostic;
278: 		const range = new vscode.Range(typeConverters.Position.fromLocation(start), typeConverters.Position.fromLocation(end));
279: 		const converted = new vscode.Diagnostic(range, text, this.getDiagnosticSeverity(diagnostic));
280: 		converted.source = diagnostic.source || source;
281: 		if (diagnostic.code) {
282: 			converted.code = diagnostic.code;
283: 		}
284: 		const relatedInformation = diagnostic.relatedInformation;
285: 		if (relatedInformation) {
286: 			converted.relatedInformation = coalesce(relatedInformation.map((info: any) => {
287: 				const span = info.span;
288: 				if (!span) {
289: 					return undefined;
290: 				}
291: 				return new vscode.DiagnosticRelatedInformation(typeConverters.Location.fromTextSpan(this.client.toResource(span.file), span), info.message);
292: 			}));
293: 		}
294: 		const tags: vscode.DiagnosticTag[] = [];
295: 		if (diagnostic.reportsUnnecessary) {
296: 			tags.push(vscode.DiagnosticTag.Unnecessary);
297: 		}
298: 		if (diagnostic.reportsDeprecated) {
299: 			tags.push(vscode.DiagnosticTag.Deprecated);
300: 		}
301: 		converted.tags = tags.length ? tags : undefined;
302: 
303: 		const resultConverted = converted as vscode.Diagnostic & { reportUnnecessary: any; reportDeprecated: any };
304: 		resultConverted.reportUnnecessary = diagnostic.reportsUnnecessary;
305: 		resultConverted.reportDeprecated = diagnostic.reportsDeprecated;
306: 		return resultConverted;
307: 	}
