310: 		if (this.reportStyleCheckAsWarnings
311: 			&& this.isStyleCheckDiagnostic(diagnostic.code)
312: 			&& diagnostic.category === PConst.DiagnosticCategory.error
313: 		) {
314: 			return vscode.DiagnosticSeverity.Warning;
315: 		}
316: 
317: 		switch (diagnostic.category) {
318: 			case PConst.DiagnosticCategory.error:
319: 				return vscode.DiagnosticSeverity.Error;
320: 
321: 			case PConst.DiagnosticCategory.warning:
322: 				return vscode.DiagnosticSeverity.Warning;
323: 
